1	import * as Sentry from '@sentry/nextjs';
2	
3	import { isAppError, isExpectedError } from '@/lib/errors';
4	
5	/**
6	 * Placeholder value used when sensitive fields are redacted before being sent
7	 * to Sentry.
8	 */
9	const REDACTED_VALUE = '[REDACTED]';
10	
11	/**
12	 * Simple marker returned when circular object references are encountered during
13	 * context sanitization.
14	 */
15	const CIRCULAR_REFERENCE_VALUE = '[CIRCULAR]';
16	
17	/**
18	 * Marker returned when context traversal reaches the configured recursion limit.
19	 */
20	const TRUNCATED_VALUE = '[TRUNCATED]';
21	
22	/**
23	 * Maximum object/array nesting depth processed when sanitizing extra context
24	 * before capture.
25	 */
26	const MAX_REDACTION_DEPTH = 6;
27	
28	/**
29	 * Regex covering common sensitive key names that should never be sent to
30	 * Sentry payloads.
31	 */
32	const SENSITIVE_KEY_PATTERN = /(token|password|authorization|cookie|secret|session|api[-_]?key)/i;
33	
34	/**
35	 * Primitive input values accepted in dynamic Sentry tag maps.
36	 */
37	type TagValue = string | number | boolean | null | undefined;
38	
39	/**
40	 * Context accepted by {@link captureUnexpectedError}.
41	 */
42	interface CaptureUnexpectedErrorContext {
43	    /**
44	     * Logical layer where the error occurred (for example: `client`, `route`,
45	     * `server-action`, `service`).
46	     */
47	    layer?: string;
48	    /**
49	     * High-level action associated with the failing operation.
50	     */
51	    action?: string;
52	    /**
53	     * Component name when capture happens in the React layer.
54	     */
55	    component?: string;
56	    /**
57	     * Route or endpoint identifier associated with the error.
58	     */
59	    route?: string;
60	    /**
61	     * Optional additional tag values.
62	     */
63	    tags?: Record<string, TagValue>;
64	    /**
65	     * Optional additional context, sanitized before being attached to Sentry.
66	     */
67	    extra?: Record<string, unknown>;
68	    /**
69	     * Optional fingerprint override for grouping customization.
70	     */
71	    fingerprint?: string[];
72	}
73	
74	/**
75	 * Returns whether a key should be treated as sensitive and therefore redacted
76	 * from Sentry extras.
77	 *
78	 * @param key Field name to inspect.
79	 * @returns `true` when the key matches known sensitive patterns.
80	 */
81	export const isSensitiveKey = (key: string): boolean =>
82	    SENSITIVE_KEY_PATTERN.test(key);
83	
84	/**
85	 * Type guard for non-null plain object-like records.
86	 *
87	 * @param value Unknown value to inspect.
88	 * @returns `true` when the value is an object record.
89	 */
90	const isObjectRecord = (value: unknown): value is Record<string, unknown> =>
91	    typeof value === 'object' && value !== null;
92	
93	/**
94	 * Redacts sensitive values and recursively sanitizes nested data before it is
95	 * attached to Sentry as `extra` context.
96	 *
97	 * @param value Input value to sanitize.
98	 * @param depth Current recursion depth.
99	 * @param seen Set used to detect circular references.
100	 * @returns Sanitized value safe for observability payloads.
101	 */
102	const sanitizeExtraValue = (
103	    value: unknown,
104	    depth: number,
105	    seen: WeakSet<object>,
106	): unknown => {
107	    if (depth >= MAX_REDACTION_DEPTH) {
108	        return TRUNCATED_VALUE;
109	    }
110	
111	    if (!isObjectRecord(value)) {
112	        return value;
113	    }
114	
115	    if (value instanceof Date) {
116	        return value.toISOString();
117	    }
118	
119	    if (value instanceof Error) {
120	        return {
121	            name: value.name,
122	            message: value.message,
123	        };
124	    }
125	
126	    if (seen.has(value)) {
127	        return CIRCULAR_REFERENCE_VALUE;
128	    }
129	    seen.add(value);
130	
131	    if (Array.isArray(value)) {
132	        return value.map((entry) =>
133	            sanitizeExtraValue(entry, depth + 1, seen));
134	    }
135	
136	    const sanitized: Record<string, unknown> = {};
137	
138	    for (const [key, entryValue] of Object.entries(value)) {
139	        sanitized[key] = isSensitiveKey(key) ?
140	            REDACTED_VALUE :
141	            sanitizeExtraValue(entryValue, depth + 1, seen);
142	    }
143	
144	    return sanitized;
145	};
146	
147	/**
148	 * Converts a tag value to a Sentry-compatible string, dropping nullish values.
149	 *
150	 * @param value Tag value candidate.
151	 * @returns Normalized string value or `undefined` when the value should be
152	 * omitted.
153	 */
154	const toTagString = (value: TagValue): string | undefined => {
155	    if (value == null) {
156	        return undefined;
157	    }
158	    return String(value);
159	};
160	
161	/**
162	 * Builds a normalized tag object for Sentry capture from fixed and dynamic
163	 * context properties.
164	 *
165	 * @param error Original thrown value.
166	 * @param context Capture context metadata.
167	 * @returns Record of normalized Sentry tags.
168	 */
169	const buildTags = (
170	    error: unknown,
171	    context: CaptureUnexpectedErrorContext,
172	): Record<string, string> => {
173	    const tags: Record<string, string> = {};
174	    const fixedTags = {
175	        layer: context.layer,
176	        action: context.action,
177	        component: context.component,
178	        route: context.route,
179	    };
180	
181	    for (const [key, value] of Object.entries(fixedTags)) {
182	        const normalized = toTagString(value);
183	        if (normalized !== undefined) {
184	            tags[key] = normalized;
185	        }
186	    }
187	
188	    for (const [key, value] of Object.entries(context.tags ?? {})) {
189	        const normalized = toTagString(value);
190	        if (normalized !== undefined) {
191	            tags[key] = normalized;
192	        }
193	    }
194	
195	    if (isAppError(error)) {
196	        tags.app_error_code = error.code;
197	    }
198	
199	    return tags;
200	};
201	
202	/**
203	 * Normalizes non-Error throwables to Error instances so stack/error semantics
204	 * are consistent in Sentry.
205	 *
206	 * @param error Unknown thrown value.
207	 * @returns Error instance suitable for Sentry capture.
208	 */
209	const toThrowableError = (error: unknown): Error => {
210	    if (error instanceof Error) {
211	        return error;
212	    }
213	    return new Error('Non-Error value thrown.', { cause: error });
214	};
215	
216	/**
217	 * Captures only unexpected failures to Sentry with common tagging and sanitized
218	 * context.
219	 *
220	 * Expected errors are skipped intentionally to reduce noise and free-tier quota
221	 * burn. The function returns a boolean to make this behaviour testable and to
222	 * allow callers to branch if needed.
223	 *
224	 * @param error Unknown thrown value to evaluate for capture.
225	 * @param context Optional capture context (tags, extras, fingerprints).
226	 * @returns `true` when an event was captured; otherwise `false`.
227	 */
228	export const captureUnexpectedError = (
229	    error: unknown,
230	    context: CaptureUnexpectedErrorContext = {},
231	): boolean => {
232	    if (isExpectedError(error)) {
233	        return false;
234	    }
235	
236	    const throwable = toThrowableError(error);
237	    const tags = buildTags(error, context);
238	    /**
239	     * Tracks visited objects during sanitization to detect circular references
240	     * across all values processed for this capture operation.
241	     */
242	    const visitedObjects = new WeakSet<object>();
243	    const extra = sanitizeExtraValue(context.extra ?? {}, 0, visitedObjects);
244	    const extraRecord = isObjectRecord(extra) ? { ...extra } : {};
245	
246	    if (!(error instanceof Error)) {
247	        extraRecord.thrownValue = sanitizeExtraValue(error, 0, visitedObjects);
248	    }
249	
250	    Sentry.captureException(throwable, {
251	        tags: Object.keys(tags).length > 0 ? tags : undefined,
252	        extra: Object.keys(extraRecord).length > 0 ? extraRecord : undefined,
253	        fingerprint: context.fingerprint,
254	    });
255	
256	    return true;
257	};
