1	import type { TeamName } from 'prisma/zod/schemas';
2	
3	import type { TeamPlayerType } from '@/types';
4	import type { PointsValue } from '@/types/Points';
5	
6	export type GameWinner = TeamName | 'draw' | null;
7	export type TeamResultState = 'win' | 'loss' | 'draw' | 'unset';
8	
9	// TODO: It feels like these should be unnecessary and the winner should be a
10	// single database query, for example.
11	
12	/**
13	 * Determines the unanimous points outcome for a team.
14	 *
15	 * Returns the points value (0, 1, or 3) if all players in the team have the
16	 * same points outcome. Returns null if the team is empty, if any player has an
17	 * invalid points value, or if players have different points values.
18	 *
19	 * @param team - An array of team players with outcome information
20	 * @returns The unanimous points value (0, 1, or 3) if all players agree,
21	 * otherwise null
22	 *
23	 * @example
24	 * ```typescript
25	 * const team = [
26	 *   { outcome: { points: 3 } },
27	 *   { outcome: { points: 3 } }
28	 * ];
29	 * pickTeamPoints(team); // returns 3
30	 * ```
31	 *
32	 * @example
33	 * ```typescript
34	 * const team = [
35	 *   { outcome: { points: 3 } },
36	 *   { outcome: { points: 1 } }
37	 * ];
38	 * pickTeamPoints(team); // returns null (different points)
39	 * ```
40	 */
41	const pickTeamPoints = (team: TeamPlayerType[]): PointsValue | null => {
42	    if (team.length === 0) return null;
43	    const distinctPoints = new Set<PointsValue>();
44	
45	    // TODO: Run this check across history since it shouldn't happen
46	    for (const player of team) {
47	        const points = player.outcome.points;
48	        if (points !== 0 && points !== 1 && points !== 3) {
49	            return null;
50	        }
51	        distinctPoints.add(points);
52	    }
53	
54	    if (distinctPoints.size !== 1) return null;
55	
56	    return Array.from(distinctPoints)[0] ?? null;
57	};
58	
59	/**
60	 * Determines the winner of a game based on team points.
61	 * @param teamA - Array of players in team A
62	 * @param teamB - Array of players in team B
63	 * @returns The game winner ('A', 'B', or 'draw'), or null if the result is invalid or undetermined
64	 */
65	export const getGameWinnersFromTeams = (
66	    teamA: TeamPlayerType[],
67	    teamB: TeamPlayerType[],
68	): GameWinner => {
69	    const pointsA = pickTeamPoints(teamA);
70	    const pointsB = pickTeamPoints(teamB);
71	
72	    if (pointsA === null || pointsB === null) return null;
73	    if (pointsA === 1 && pointsB === 1) return 'draw';
74	    if (pointsA === 3 && pointsB === 0) return 'A';
75	    if (pointsA === 0 && pointsB === 3) return 'B';
76	
77	    return null;
78	};
79	
80	/**
81	 * Determines the result state for a specific team based on the game winner.
82	 *
83	 * @param team - The name of the team to check the result for
84	 * @param winner - The winner of the game (can be a team name, 'draw', or null)
85	 * @returns The result state for the specified team:
86	 *   - 'unset' if the winner is null (game not yet decided)
87	 *   - 'draw' if the game ended in a draw
88	 *   - 'win' if the specified team won
89	 *   - 'loss' if the specified team lost
90	 */
91	export const getTeamResultState = (
92	    team: TeamName,
93	    winner: GameWinner,
94	): TeamResultState => {
95	    if (winner === null) return 'unset';
96	    if (winner === 'draw') return 'draw';
97	    if (winner === team) return 'win';
98	    return 'loss';
99	};
