11	/**
12	 * Structured context attached to errors created from failed HTTP responses.
13	 */
14	interface RequestErrorDetails {
15	    status: number;
16	    statusText: string;
17	    url?: string;
18	    method?: string;
19	}
20	
21	interface ToRequestErrorOptions {
22	    method?: string;
23	    fallbackMessage?: string;
24	}
25	
26	/**
27	 * Best-effort extraction of a public-facing message from a failed HTTP
28	 * response body.
29	 */
30	const extractResponseMessage = (bodyText: string): string | undefined => {
31	    const trimmed = bodyText.trim();
32	    if (!trimmed) {
33	        return undefined;
34	    }
35	
36	    if (trimmed.startsWith('{') || trimmed.startsWith('[')) {
37	        try {
38	            const parsed = JSON.parse(trimmed) as unknown;
39	            if (parsed && typeof parsed === 'object') {
40	                if ('message' in parsed && typeof parsed.message === 'string') {
41	                    return parsed.message;
42	                }
43	                if ('error' in parsed && typeof parsed.error === 'string') {
44	                    return parsed.error;
45	                }
46	            }
47	        } catch {
48	            // Fall through to plain-text handling when JSON parsing fails.
49	        }
50	    }
51	
52	    return trimmed.replace(/^Error:\s*/i, '');
53	};
54	
55	/**
56	 * Creates a typed app error from a non-2xx HTTP response.
57	 *
58	 * Status codes are mapped to existing AppError subclasses so callers can
59	 * preserve expected/unsupported classification semantics.
60	 */
61	export const toRequestError = async (
62	    response: Response,
63	    options: ToRequestErrorOptions = {},
64	): Promise<AppError> => {
65	    const bodyText = await response.text().catch(() => '');
66	    const extractedMessage = extractResponseMessage(bodyText);
67	    const fallbackMessage = options.fallbackMessage ?? 'Request failed.';
68	    const publicMessage = extractedMessage ?? fallbackMessage;
69	    const details: RequestErrorDetails = {
70	        status: response.status,
71	        statusText: response.statusText,
72	        url: response.url || undefined,
73	        method: options.method,
74	    };
75	    const internalMessage = `HTTP ${response.status} ${response.statusText}${response.url ? ` for ${response.url}` : ''}`;
76	
77	    switch (response.status) {
78	        case 400:
79	            return new ValidationError(internalMessage, {
80	                publicMessage,
81	                details,
82	            });
83	        case 401:
84	        case 403:
85	            return new AuthError(internalMessage, {
86	                publicMessage,
87	                details,
88	            });
89	        case 404:
90	            return new NotFoundError(internalMessage, {
91	                publicMessage,
92	                details,
93	            });
94	        case 409:
95	            return new ConflictError(internalMessage, {
96	                publicMessage,
97	                details,
98	            });
99	        case 502:
100	        case 503:
101	        case 504:
102	            return new ExternalServiceError(internalMessage, {
103	                publicMessage,
104	                details,
105	            });
106	        default:
107	            if (response.status >= 400 && response.status < 500) {
108	                return new ValidationError(internalMessage, {
109	                    publicMessage,
110	                    details,
111	                });
112	            }
113	            return new InternalError(internalMessage, {
114	                publicMessage,
115	                details,
116	            });
117	    }
118	};
