35	interface AnyElement { type: unknown; props: Record<string, unknown> }
36	
37	const findElement = (node: unknown, name: string): AnyElement | null => {
38	    if (!node || typeof node !== 'object') return null;
39	    const el = node as AnyElement;
40	    if (typeof el.type === 'function') {
41	        const fn = el.type as { displayName?: string; name?: string };
42	        const elName = fn.displayName ?? fn.name;
43	        if (elName === name) return el;
44	    }
45	    const children = (el.props as { children?: unknown }).children;
46	    if (Array.isArray(children)) {
47	        for (const child of children) {
48	            const found = findElement(child, name);
49	            if (found) return found;
50	        }
51	    }
52	    return findElement(children, name);
53	};
