3	import { notFound, permanentRedirect } from 'next/navigation';
4	import { cache } from 'react';
5	import z from 'zod';
6	
7	import { AutoRefresh } from '@/components/AutoRefresh/AutoRefresh';
8	import { GameDayList } from '@/components/GameDayList/GameDayList';
9	import { TitleWithYearDropdown } from '@/components/TitleWithYearDropdown/TitleWithYearDropdown';
10	import { getYearName } from '@/lib/tables';
11	import gameDayService from '@/services/GameDay';
12	import { FootyChannel } from '@/types/FootyChannel';
13	
14	interface PageProps {
15	    searchParams?: Promise<{
16	        year?: string;
17	    }>;
18	}
19	
20	/**
21	 * Asynchronously unpacks and validates search parameters for the footy games
22	 * page, fetching relevant data such as available years, the current game day,
23	 * and game statistics.
24	 *
25	 * - Validates the `year` parameter from the search params, ensuring it is a
26	 *   valid year present in the list of all years.
27	 * - If the year is invalid or missing, triggers a 404 not found response.
28	 * - Fetches the number of games played, cancelled, and remaining for the
29	 *   specified year.
30	 * - Ensures the canonical URL structure by redirecting if the current URL does
31	 *   not match the canonical format.
32	 * - Constructs a title and subhead string summarizing the games data.
33	 *
34	 * @param searchParams - The search parameters from the page props, expected to
35	 * include a `year` query parameter.
36	 * @returns An object containing the validated year, all available years, the
37	 * current game day, a title, and a subhead string.
38	 * @throws Redirects to the canonical URL if the current URL is not canonical.
39	 * @throws Triggers a 404 not found response if the year is invalid or not
40	 * present in the available years.
41	 */
42	const unpackParams = cache(async (
43	    searchParams: PageProps['searchParams'],
44	) => {
45	    const [resolvedSearchParams, allYears, currentGameDay] = await Promise.all([
46	        searchParams,
47	        gameDayService.getAllYears({
48	            includeAllTime: true,
49	            mostRecentFirst: true,
50	        }),
51	        gameDayService.getCurrent(),
52	    ]);
53	    const yearResult = z.coerce.number().int().min(0).safeParse(resolvedSearchParams?.year ?? 0);
54	    const year = yearResult.success ? yearResult.data : undefined;
55	    if (year === undefined || !allYears.includes(year)) notFound();
56	
57	    const [gamesPlayed, gamesCancelled, gamesRemaining] = await Promise.all([
58	        gameDayService.getGamesPlayed(year, currentGameDay?.id),
59	        gameDayService.getGamesCancelled(year, currentGameDay?.id),
60	        gameDayService.getGamesRemaining(year),
61	    ]);
62	
63	    const canonicalSearch = year !== undefined ? `?year=${year}` : '';
64	    const canonicalUrl = `/footy/games/${canonicalSearch}`;
65	    const currentSearch = resolvedSearchParams?.year !== undefined ?
66	        `?year=${resolvedSearchParams.year}` :
67	        '';
68	    const currentUrl = `/footy/games/${currentSearch}`;
69	    if (currentUrl !== canonicalUrl) permanentRedirect(canonicalUrl);
70	
71	    const title = `${year ? `${year} ` : ''}Games`;
72	    const subheadValues = [];
73	    if (gamesPlayed) subheadValues.push(`${gamesPlayed} played`);
74	    if (gamesCancelled) subheadValues.push(`${gamesCancelled} cancelled`);
75	    if (gamesRemaining) subheadValues.push(`${gamesRemaining} confirmed`);
76	    const subhead = subheadValues.join(', ');
77	
78	    return { year, allYears, currentGameDay, title, subhead };
79	});
80	
81	/**
82	 * Generates metadata for the footy games page based on the provided search
83	 * parameters. Fetches the year from the search parameters and constructs a
84	 * title for the page using the year name. If the year is not provided or
85	 * invalid, it defaults to a generic title.
86	 * @param props - The page properties containing search parameters.
87	 * @returns A promise that resolves to a Metadata object with the generated
88	 * title.
89	 * @throws Redirects to the canonical URL if the current URL is not canonical.
90	 * @throws Triggers a 404 not found response if the year is invalid or not
91	 * present in the available years.
92	 */
93	export async function generateMetadata(props: PageProps): Promise<Metadata> {
94	    const { year } = await unpackParams(props.searchParams);
95	    return { title: `${getYearName(year)} Games` };
96	}
97	
98	/**
99	 * Server page component for displaying footy games. Fetches and validates the year from the search parameters, retrieves the list of game days for that year,
100	 * and renders a page with a title, subhead, and a list of game days. Also
101	 * includes an auto-refresh component that listens to relevant channels for
102	 * updates.
103	 * @param props - The page properties containing search parameters.
104	 * @returns A React element representing the games page.
105	 * @throws Redirects to the canonical URL if the current URL is not canonical.
106	 * @throws Triggers a 404 not found response if the year is invalid or not
107	 * present in the available years.
108	 * @remarks The page includes an auto-refresh mechanism that listens to the
109	 * "Games" and "Results" channels for real-time updates, ensuring that the
110	 * displayed data remains current without requiring manual refreshes.
111	 */
112	const GamesPage = async (props: PageProps) => {
113	    const { year, allYears, subhead } = await unpackParams(props.searchParams);
114	    const gameDays = await gameDayService.getAll({ year });
115	
116	    return (
117	        <Flex direction="column" align="center" gap="lg">
118	            <AutoRefresh channels={[FootyChannel.Games, FootyChannel.Results]} />
119	            <Group justify="center" w="100%">
120	                <TitleWithYearDropdown order={1} title="Games: " year={year} validYears={allYears} />
121	            </Group>
122	            <Title order={2}>{subhead}</Title>
123	            <GameDayList gameDays={gameDays} year={year} />
124	        </Flex>
125	    );
126	};
127	
128	export default GamesPage;
129

