9	/**
10	 * Adds a specified number of days to a given date.
11	 *
12	 * @param date - The base date to add days to
13	 * @param days - The number of days to add (can be negative to subtract days)
14	 * @returns A new Date object with the specified number of days added
15	 *
16	 * @example
17	 * ```ts
18	 * const today = new Date('2024-01-01');
19	 * const nextWeek = addDays(today, 7); // 2024-01-08
20	 * const lastWeek = addDays(today, -7); // 2023-12-25
21	 * ```
22	 */
23	const addDays = (date: Date, days: number) => {
24	    const next = new Date(date);
25	    next.setDate(next.getDate() + days);
26	    return next;
27	};
28	
29	/**
30	 * Normalizes a date to 6:00 PM (18:00) on the same day.
31	 *
32	 * @param date - The date to normalize
33	 * @returns A new Date object set to 18:00:00.000 on the same day as the input date
34	 */
35	const normalizeGameDayTime = (date: Date) => {
36	    return new Date(date.getFullYear(), date.getMonth(), date.getDate(), 18, 0, 0, 0);
37	};
38	
39	/**
40	 * Calculates the booking year end date based on the given date. The booking
41	 * year runs from August 1st to July 31st. If the date is in August or later
42	 * (month >= 7), returns July 31st of the following year at 18:00:00. Otherwise,
43	 * returns July 31st of the current year at 18:00:00.
44	 *
45	 * @param date - The date to calculate the booking year end from
46	 * @returns A Date object representing the end of the booking year (July 31st at
47	 * 18:00:00)
48	 */
49	const getBookingYearEnd = (date: Date) => {
50	    const year = date.getFullYear();
51	    const isAfterJuly = date.getMonth() >= 7;
52	    const endYear = isAfterJuly ? year + 1 : year;
53	    return new Date(endYear, 6, 31, 18, 0, 0, 0);
54	};
55	
56	/**
57	 * Calculates the date of the next Tuesday from a given date. If the given date
58	 * is a Tuesday, returns the following Tuesday (7 days later).
59	 *
60	 * @param from - The reference date to calculate from
61	 * @returns A Date object representing the next Tuesday after the given date
62	 *
63	 * @example
64	 * ```ts
65	 * const nextTuesday = getNextTuesday(new Date('2024-01-15')); // Returns Tuesday, Jan 16
66	 * const fromTuesday = getNextTuesday(new Date('2024-01-16')); // Returns Tuesday, Jan 23
67	 * ```
68	 */
69	const getNextTuesday = (from: Date) => {
70	    const day = from.getDay();
71	    const daysUntilTuesday = (2 - day + 7) % 7;
72	    const candidate = addDays(from, daysUntilTuesday);
73	    return candidate <= from ? addDays(candidate, 7) : candidate;
74	};
75	
76	/**
77	 * Builds an array of weekly game rows from a start date to the end of the
78	 * booking year.
79	 *
80	 * Each row represents a game scheduled 7 days apart, starting from the given
81	 * date and continuing until the booking year end date (inclusive).
82	 *
83	 * @param startDate - The date to begin scheduling games from
84	 * @returns An array of game row objects, each containing:
85	 *   - `date`: ISO format date string (YYYY-MM-DD)
86	 *   - `game`: Boolean flag set to true indicating a game is scheduled
87	 *   - `comment`: Empty string for additional notes
88	 */
89	const buildRows = (startDate: Date) => {
90	    const endDate = getBookingYearEnd(startDate);
91	    const rows = [];
92	
93	    for (let date = new Date(startDate); date <= endDate; date = addDays(date, 7)) {
94	        rows.push({
95	            date: formatDate(date),
96	            game: true,
97	            comment: '',
98	        });
99	    }
100	
101	    return rows;
102	};
