22	    if (!node || typeof node !== 'object') return null;
23	    if (Array.isArray(node)) {
24	        for (const child of node) {
25	            const found = findElement(child, name);
26	            if (found) return found;
27	        }
28	        return null;
29	    }
30	    const el = node as AnyElement;
31	    if (typeof el.type === 'function') {
32	        const fn = el.type as { displayName?: string; name?: string };
33	        const elName = fn.displayName ?? fn.name;
34	        if (elName === name) return el;
35	    }
36	    const children = (el.props as { children?: unknown } | undefined)?.children;
37	    return findElement(children, name);
38	};
