41	const findElement = (node: unknown, name: string): AnyElement | null => {
42	    if (!node || typeof node !== 'object') return null;
43	    if (Array.isArray(node)) {
44	        for (const child of node) {
45	            const found = findElement(child, name);
46	            if (found) return found;
47	        }
48	        return null;
49	    }
50	    const el = node as AnyElement;
51	    if (typeof el.type === 'function') {
52	        const fn = el.type as { displayName?: string; name?: string };
53	        const elName = fn.displayName ?? fn.name;
54	        if (elName === name) return el;
55	    }
56	    const children = (el.props as { children?: unknown } | undefined)?.children;
57	    return findElement(children, name);
58	};
